mapper.select:
SELECT d.id FROM dish d LEFT JOIN user_behavior ub ON d.id = ub.dish_id WHERE d.category_id IN
#{categoryId}
AND d.status = 1 GROUP BY d.id ORDER BY COUNT(ub.id) DESC, d.create_time DESC LIMIT #{limit}

SELECT od.dish_id
FROM order_detail od
         INNER JOIN orders o ON od.order_id = o.id
         INNER JOIN user_behavior ub ON o.user_id = ub.user_id
WHERE ub.dish_id = #{dishId}
  AND od.dish_id != #{dishId}
GROUP BY od.dish_id
ORDER BY COUNT(*) DESC
    LIMIT #{limit}
